        "sensor.humidity_living_room",
        "binary_sensor.motion_hall",
    ]

    try:
        # 获取音箱状态数据
        speaker_data = tool_get_states_by_entity_id({"entity_id": SPEAKER_ENTITY_ID})

        # 读取其他传感器数据（不会影响主功能的返回值）
        additional_data = {}
        for sensor_entity in ADDITIONAL_SENSORS:
            try:
                additional_data[sensor_entity] = tool_get_states_by_entity_id({"entity_id": sensor_entity})
            except Exception as se:
                additional_data[sensor_entity] = {"error": str(se)}

        # 可以根据需要将 additional_data 进行处理或记录，这里简单打印以便调试
        try:
            print("Additional sensor data:", additional_data)
        except Exception:
            pass

        # 直接读取静音状态字段（true=静音，false=未静音）
        return speaker_data["attributes"].get("is_volume_muted", False)

    except Exception as e:
        # 数据获取失败时返回False
        print(f"音箱静音状态检测异常：{e}")
        return False
